import java.io.IOException;
import java.io.PrintWriter;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        // Simulating user input from a form submission
        String userInput = "<script>alert('XSS Attack!');</script>";

        // Sanitize the user input to prevent XSS attacks
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Displaying sanitized user input on a web page
        PrintWriter out = new PrintWriter("index.html");
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Welcome " + sanitizedInput + "</h1>");
        out.println("</body>");
        out.println("</html>");

        out.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
